<!DOCTYPE html>
<html lang="id">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Wedding Organizations</title>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;1,400;1,500&family=DM+Sans:wght@300;400;500&family=Pinyon+Script&display=swap" rel="stylesheet">

<style>
/* ── RESET & BASE ── */
*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

:root {
    --cream:    #FAF8FF;
    --ivory:    #F0ECF8;
    --blush:    #C8B8E0;
    --rose:     #9A80C0;
    --deep:     #5A3A80;
    --gold:     #C8B070;
    --charcoal: #1A1020;
    --warm-mid: #7A6090;
    --glass-bg: rgba(248, 244, 255, 0.82);
}

html, body { height: 100%; }

body {
    font-family: 'DM Sans', sans-serif;
    background-color: var(--cream);
    color: var(--charcoal);
    overflow-x: hidden;
    min-height: 100vh;
    position: relative;
}

/* ── BACKGROUND ── */
.bg-layer {
    position: fixed;
    inset: 0;
    z-index: 0;
    background-image: url("data:image/jpeg;base64,");
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
}

/* Overlay for readability */
.bg-layer::before {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(
        to bottom,
        rgba(10,5,20,0.52) 0%,
        rgba(20,10,40,0.28) 50%,
        rgba(10,5,20,0.55) 100%
    );
}

/* ── OVERLAY (sidebar backdrop) ── */
.overlay {
    display: none;
    position: fixed;
    inset: 0;
    background: rgba(42, 36, 32, 0.45);
    z-index: 400;
    backdrop-filter: blur(4px);
    -webkit-backdrop-filter: blur(4px);
    transition: opacity 0.3s;
}
.overlay.active { display: block; }

/* ── SIDEBARS ── */
.sidebar {
    position: fixed;
    top: 0; bottom: 0;
    width: 280px;
    z-index: 500;
    padding: 0;
    transition: transform 0.5s cubic-bezier(0.77, 0, 0.175, 1);
}

.sidebar-left {
    left: 0;
    transform: translateX(-100%);
    background: var(--charcoal);
    border-right: 1px solid rgba(184, 151, 106, 0.2);
}
.sidebar-right {
    right: 0;
    transform: translateX(100%);
    background: var(--charcoal);
    border-left: 1px solid rgba(184, 151, 106, 0.2);
}
.sidebar.active { transform: translateX(0); }

.sidebar-inner {
    padding: 90px 0 40px;
    height: 100%;
    display: flex;
    flex-direction: column;
}

.sidebar-label {
    font-size: 0.6rem;
    letter-spacing: 0.22em;
    text-transform: uppercase;
    color: var(--gold);
    padding: 0 32px 20px;
    font-weight: 500;
    opacity: 0.7;
}

.sidebar-right .sidebar-label { text-align: right; }

.sidebar-menu { list-style: none; flex: 1; }

.sidebar-menu li a {
    display: block;
    padding: 14px 32px;
    font-family: 'Playfair Display', serif;
    font-size: 1.05rem;
    color: rgba(250, 246, 240, 0.75);
    text-decoration: none;
    transition: all 0.25s ease;
    position: relative;
    letter-spacing: 0.02em;
}

.sidebar-menu li a::before {
    content: '';
    position: absolute;
    left: 0; top: 50%;
    transform: translateY(-50%);
    width: 2px; height: 0;
    background: var(--gold);
    transition: height 0.25s ease;
}

.sidebar-menu li a:hover {
    color: var(--cream);
    padding-left: 40px;
}
.sidebar-menu li a:hover::before { height: 60%; }

.sidebar-right .sidebar-menu li a { text-align: right; }
.sidebar-right .sidebar-menu li a::before { left: auto; right: 0; }
.sidebar-right .sidebar-menu li a:hover { padding-left: 32px; padding-right: 40px; }

.sidebar-menu li a.danger { color: var(--rose); }
.sidebar-menu li a.danger:hover { color: #e8a09a; }

/* Sidebar bottom accent */
.sidebar-accent {
    padding: 24px 32px;
    border-top: 1px solid rgba(184, 151, 106, 0.15);
    font-family: 'Pinyon Script', cursive;
    font-size: 2rem;
    color: rgba(184, 151, 106, 0.3);
    text-align: center;
}

/* ── HEADER ── */
.header {
    position: relative;
    z-index: 10;
    width: 100%;
    height: 72px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 32px;
    background: rgba(15, 8, 28, 0.72);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border-bottom: 1px solid rgba(184, 151, 106, 0.2);
}

/* Logo center */
.header-logo {
    position: absolute;
    left: 50%;
    transform: translateX(-50%);
    font-family: 'Pinyon Script', cursive;
    font-size: 1.9rem;
    color: #FFFFFF;
    letter-spacing: 0.02em;
    pointer-events: none;
    white-space: nowrap;
}

/* Profile btn */
.btn-profile {
    width: 42px; height: 42px;
    background: var(--charcoal);
    border: none;
    border-radius: 50%;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    color: var(--cream);
    text-decoration: none;
    transition: background 0.2s, transform 0.2s;
    flex-shrink: 0;
}
.btn-profile:hover { background: var(--rose); transform: scale(1.05); }

/* Hamburger */
.btn-hamburger {
    display: flex; flex-direction: column; gap: 5px;
    background: none; border: none;
    cursor: pointer; padding: 6px;
    flex-shrink: 0;
}
.btn-hamburger span {
    display: block;
    width: 24px; height: 2px;
    background: rgba(255,255,255,0.85);
    border-radius: 2px;
    transition: background 0.2s;
}
.btn-hamburger:hover span { background: #C8A8F0; }

/* ── MAIN CONTENT ── */
.main {
    position: relative;
    z-index: 1;
    min-height: calc(100vh - 72px);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 40px 24px 80px;
}

/* ── HERO TEXT ── */
.hero {
    text-align: center;
    margin-bottom: 40px;
    animation: fadeUp 0.8s ease both;
}

.hero-eyebrow {
    font-size: 0.65rem;
    letter-spacing: 0.28em;
    text-transform: uppercase;
    color: #FFFFFF;
    font-weight: 500;
    margin-bottom: 12px;
    display: block;
}

.hero-title {
    font-family: 'Playfair Display', serif;
    font-size: clamp(2.4rem, 6vw, 3.8rem);
    font-weight: 400;
    color: #FFFFFF;
    line-height: 1.1;
    text-shadow: 0 2px 30px rgba(0,0,0,0.6);
    letter-spacing: -0.01em;
    margin-bottom: 6px;
}

.hero-title em {
    font-style: italic;
    color: #FFFFFF;
}

.hero-subtitle {
    font-size: 0.85rem;
    color: rgba(255,255,255,0.90);
    letter-spacing: 0.04em;
    margin-top: 10px;
}

/* Decorative rule */
.hero-rule {
    display: flex;
    align-items: center;
    gap: 14px;
    justify-content: center;
    margin: 18px 0 0;
}
.hero-rule::before, .hero-rule::after {
    content: '';
    height: 1px;
    width: 60px;
    background: linear-gradient(90deg, transparent, var(--gold));
}
.hero-rule::after { background: linear-gradient(90deg, var(--gold), transparent); }
.hero-rule-diamond {
    width: 6px; height: 6px;
    background: rgba(255,255,255,0.7);
    transform: rotate(45deg);
}

/* ── SEARCH CARD ── */
.search-card {
    width: 100%;
    max-width: 440px;
    background: rgba(248, 244, 255, 0.86);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border: 1px solid rgba(184, 151, 106, 0.25);
    border-radius: 24px;
    padding: 32px 32px 28px;
    box-shadow:
        0 2px 0 rgba(255,255,255,0.8) inset,
        0 20px 60px rgba(42, 36, 32, 0.1),
        0 4px 12px rgba(42, 36, 32, 0.06);
    animation: fadeUp 0.9s 0.1s ease both;
    position: relative;
    overflow: hidden;
}

/* Top inner glow */
.search-card::before {
    content: '';
    position: absolute;
    top: 0; left: 10%; right: 10%;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(184,151,106,0.5), transparent);
}

/* ── TABS ── */
.tabs {
    display: flex;
    background: rgba(122, 63, 56, 0.06);
    border-radius: 100px;
    padding: 4px;
    margin-bottom: 24px;
    gap: 4px;
}

.tab {
    flex: 1;
    padding: 10px 18px;
    text-align: center;
    font-size: 0.75rem;
    font-weight: 500;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    cursor: pointer;
    border-radius: 100px;
    transition: all 0.3s ease;
    color: var(--warm-mid);
    user-select: none;
}

.tab.active {
    background: var(--charcoal);
    color: var(--cream);
    box-shadow: 0 4px 16px rgba(42, 36, 32, 0.25);
    letter-spacing: 0.14em;
}

.tab:not(.active):hover { background: rgba(122, 63, 56, 0.08); color: var(--deep); }

/* ── FIELDS ── */
.field { margin-bottom: 16px; }

.field-label {
    font-size: 0.62rem;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    color: #7A5A9A;
    margin-bottom: 7px;
    font-weight: 500;
    padding-left: 4px;
}

.field select,
.field input[type="date"],
.field input[type="text"] {
    width: 100%;
    padding: 13px 20px;
    border: 1.5px solid rgba(184, 151, 106, 0.2);
    border-radius: 14px;
    background: rgba(255, 255, 255, 0.75);
    font-family: 'DM Sans', sans-serif;
    font-size: 0.88rem;
    color: var(--charcoal);
    outline: none;
    appearance: none;
    -webkit-appearance: none;
    transition: border-color 0.2s, background 0.2s, box-shadow 0.2s;
}

.field select::placeholder,
.field input::placeholder { color: rgba(122,63,56,0.4); }

.field select:focus,
.field input:focus {
    border-color: var(--gold);
    background: rgba(255,255,255,0.9);
    box-shadow: 0 0 0 3px rgba(184, 151, 106, 0.12);
}

.select-wrap { position: relative; }
.select-wrap::after {
    content: '';
    position: absolute;
    right: 18px; top: 50%;
    transform: translateY(-50%);
    width: 8px; height: 8px;
    border-right: 1.5px solid var(--gold);
    border-bottom: 1.5px solid var(--gold);
    transform: translateY(-65%) rotate(45deg);
    pointer-events: none;
}

.date-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 10px;
}

input[type="date"]::-webkit-calendar-picker-indicator {
    opacity: 0.4;
    cursor: pointer;
    filter: invert(30%) sepia(30%) saturate(400%) hue-rotate(340deg);
}

/* ── DIVIDER ── */
.divider {
    display: flex;
    align-items: center;
    gap: 12px;
    margin: 20px 0 18px;
}
.divider::before, .divider::after {
    content: '';
    flex: 1;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(184,151,106,0.3));
}
.divider::after { background: linear-gradient(90deg, rgba(184,151,106,0.3), transparent); }
.divider-icon {
    font-family: 'Pinyon Script', cursive;
    font-size: 1.4rem;
    color: rgba(255,255,255,0.7);
    line-height: 1;
    padding-bottom: 4px;
}

/* ── GO BUTTON ── */
.btn-go {
    width: 100%;
    padding: 15px;
    background: var(--charcoal);
    color: var(--cream);
    border: none;
    border-radius: 14px;
    font-family: 'DM Sans', sans-serif;
    font-size: 0.75rem;
    font-weight: 500;
    letter-spacing: 0.22em;
    text-transform: uppercase;
    cursor: pointer;
    transition: all 0.3s ease;
    position: relative;
    overflow: hidden;
}

.btn-go::before {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(135deg, var(--deep), var(--rose));
    opacity: 0;
    transition: opacity 0.35s ease;
}
.btn-go span { position: relative; z-index: 1; }

.btn-go:hover:not(:disabled)::before { opacity: 1; }
.btn-go:hover:not(:disabled) { transform: translateY(-2px); box-shadow: 0 12px 32px rgba(42,36,32,0.2); }
.btn-go:active:not(:disabled) { transform: translateY(0); }

.btn-go:disabled {
    background: rgba(42,36,32,0.15);
    color: rgba(42,36,32,0.3);
    cursor: not-allowed;
    box-shadow: none;
}
.btn-go:disabled::before { display: none; }

/* ── SUCCESS ALERT ── */
.success-alert {
    width: 100%;
    max-width: 440px;
    background: rgba(236, 253, 245, 0.9);
    border: 1px solid rgba(74, 222, 128, 0.4);
    border-radius: 16px;
    padding: 16px 20px;
    margin-bottom: 20px;
    display: flex;
    align-items: center;
    gap: 14px;
    position: relative;
    animation: fadeUp 0.5s ease;
}
.alert-icon {
    width: 30px; height: 30px;
    background: #4ade80;
    border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    color: #fff; font-size: 1rem; flex-shrink: 0;
}
.alert-content strong { font-size: 0.85rem; color: #166534; display: block; }
.alert-content p { font-size: 0.8rem; color: #15803d; }
.alert-close {
    position: absolute; top: 10px; right: 12px;
    background: none; border: none;
    font-size: 1.3rem; color: #166534;
    cursor: pointer; opacity: 0.5;
    transition: opacity 0.2s;
}
.alert-close:hover { opacity: 1; }

/* ── FOOTER CREDIT ── */
.footer-text {
    margin-top: 36px;
    font-family: 'Playfair Display', serif;
    font-style: italic;
    font-size: 0.82rem;
    color: rgba(255, 255, 255, 0.55);
    letter-spacing: 0.04em;
    animation: fadeUp 1s 0.2s ease both;
}

/* ── ANIMATIONS ── */
@keyframes fadeUp {
    from { opacity: 0; transform: translateY(20px); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ── RESPONSIVE ── */
@media (max-width: 480px) {
    .header { padding: 0 20px; }
    .header-logo { font-size: 1.5rem; }
    .search-card { padding: 24px 20px 22px; border-radius: 20px; }
    .date-row { grid-template-columns: 1fr; }
    .hero-title { font-size: 2.2rem; }
}
</style>
</head>
<body>

<div class="bg-layer"></div>
<div class="overlay" id="overlay"></div>

<!-- Left Sidebar -->
<aside class="sidebar sidebar-left" id="leftSidebar">
    <div class="sidebar-inner">
        <p class="sidebar-label">Jelajahi</p>
        <ul class="sidebar-menu">
            <li><a href="#">Gedung</a></li>
            <li><a href="#">Vendor</a></li>
            <li><a href="#">Acara</a></li>
            <li><a href="#">Tips &amp; Trik</a></li>
        </ul>
        <div class="sidebar-accent">W</div>
    </div>
</aside>

<!-- Right Sidebar -->
<aside class="sidebar sidebar-right" id="rightSidebar">
    <div class="sidebar-inner">
        <p class="sidebar-label" style="text-align:right">Akun</p>
        <ul class="sidebar-menu">
            <li><a href="#">Pemesanan Sebelumnya</a></li>
            <li><a href="#">View Rating</a></li>
            <li><a href="#">Saran</a></li>
            <li><a href="#">Study Case</a></li>
            <li><a href="#">Privasi</a></li>
            <li><a href="#" class="danger">Keluar</a></li>
        </ul>
        <div class="sidebar-accent" style="text-align:right">W</div>
    </div>
</aside>

<!-- Header -->
<header class="header">
    <a href="#" class="btn-profile" aria-label="Profil">
        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>
            <circle cx="12" cy="7" r="4"/>
        </svg>
    </a>

    <span class="header-logo">Wedding Organizations</span>

    <button class="btn-hamburger" id="toggleRight" aria-label="Menu">
        <span></span><span></span><span></span>
    </button>
</header>

<!-- Main -->
<main class="main">

    <!-- Hero -->
    <div class="hero">
        <span class="hero-eyebrow">Selamat datang</span>
        <h1 class="hero-title">Wujudkan <em>Hari Istimewa</em><br>Impian Anda</h1>
        <p class="hero-subtitle">Temukan venue & vendor terbaik untuk pernikahan sempurna</p>
        <div class="hero-rule"><div class="hero-rule-diamond"></div></div>
    </div>

    <!-- Success Alert (contoh) -->
    <!-- <div class="success-alert">
        <div class="alert-icon">✓</div>
        <div class="alert-content">
            <strong>Berhasil!</strong>
            <p>Pemesanan Anda telah dikonfirmasi.</p>
        </div>
        <button class="alert-close" onclick="this.parentElement.style.display='none'">&times;</button>
    </div> -->

    <!-- Search Card -->
    <div class="search-card">
        <div class="tabs">
            <div class="tab active" data-action="venues">Venue</div>
            <div class="tab" data-action="vendors">Vendor</div>
        </div>

        <form id="searchForm" action="#" method="GET">
            <!-- Kategori -->
            <div class="field">
                <div class="field-label">Kategori</div>
                <div class="select-wrap">
                    <select name="category" id="categorySelect">
                        <option value="" disabled selected>Pilih Kategori</option>
                    </select>
                </div>
            </div>

            <!-- Tanggal -->
            <div class="field">
                <div class="field-label">Tanggal Acara</div>
                <div class="date-row">
                    <input type="date" name="date_start" id="dateStart">
                    <input type="date" name="date_end" id="dateEnd">
                </div>
            </div>

            <!-- Lokasi -->
            <div class="field">
                <div class="field-label">Lokasi</div>
                <input type="text" name="location" id="locationInput" placeholder="Cari kota atau area...">
            </div>

            <div class="divider"><span class="divider-icon">✦</span></div>

            <button type="submit" class="btn-go" id="btnGo">
                <span>Temukan Sekarang</span>
            </button>
        </form>
    </div>

    <p class="footer-text">Crafted with love, designed for forever.</p>
</main>

<script>
    /* ── Sidebar ── */
    const leftSB  = document.getElementById('leftSidebar');
    const rightSB = document.getElementById('rightSidebar');
    const overlay = document.getElementById('overlay');

    const openSidebar = sb => { sb.classList.add('active'); overlay.classList.add('active'); };
    const closeAll    = ()  => { leftSB.classList.remove('active'); rightSB.classList.remove('active'); overlay.classList.remove('active'); };

    document.getElementById('toggleRight').addEventListener('click', e => {
        e.stopPropagation();
        rightSB.classList.contains('active') ? closeAll() : openSidebar(rightSB);
    });
    overlay.addEventListener('click', closeAll);

    /* ── Form Logic ── */
    const btnGo      = document.getElementById('btnGo');
    const categoryEl = document.getElementById('categorySelect');
    const dateStartEl= document.getElementById('dateStart');
    const dateEndEl  = document.getElementById('dateEnd');
    const locationEl = document.getElementById('locationInput');
    const tabs       = document.querySelectorAll('.tab');
    const form       = document.getElementById('searchForm');

    const venueOptions = [
        { value: 'gedung',  label: 'Gedung / Ballroom' },
        { value: 'taman',   label: 'Taman / Outdoor' },
        { value: 'resort',  label: 'Resort / Hotel' },
        { value: 'pulau',   label: 'Pulau / Tepi Laut' },
    ];
    const vendorOptions = [
        { value: 'katering',     label: 'Katering' },
        { value: 'dekorasi',     label: 'Dekorasi' },
        { value: 'mua',          label: 'Makeup Artist & Hairstylist' },
        { value: 'busana',       label: 'Busana Pengantin' },
        { value: 'dokumentasi',  label: 'Fotografer & Videografer' },
        { value: 'hiburan',      label: 'Hiburan' },
        { value: 'suvenir',      label: 'Undangan & Suvenir' },
        { value: 'kue',          label: 'Kue Pernikahan' },
        { value: 'cincin',       label: 'Cincin Pernikahan' },
        { value: 'transportasi', label: 'Transportasi & Akomodasi' },
    ];

    function checkFields() {
        const ok = categoryEl.value && dateStartEl.value && dateEndEl.value && locationEl.value.trim();
        btnGo.disabled = !ok;
    }

    function setOptions(list) {
        categoryEl.innerHTML = '<option value="" disabled selected>Pilih Kategori</option>';
        list.forEach(({ value, label }) => {
            const o = document.createElement('option');
            o.value = value; o.textContent = label;
            categoryEl.appendChild(o);
        });
        checkFields();
    }

    tabs.forEach(tab => {
        tab.addEventListener('click', () => {
            tabs.forEach(t => t.classList.remove('active'));
            tab.classList.add('active');
            setOptions(tab.dataset.action === 'vendors' ? vendorOptions : venueOptions);
        });
    });

    [categoryEl, dateStartEl, dateEndEl, locationEl].forEach(el => {
        el.addEventListener('change', checkFields);
        el.addEventListener('input',  checkFields);
    });

    form.addEventListener('submit', e => {
        if (!categoryEl.value || !dateStartEl.value || !dateEndEl.value || !locationEl.value.trim()) {
            e.preventDefault();
            alert('Harap isi semua field sebelum melanjutkan.');
        }
    });

    setOptions(venueOptions);
    btnGo.disabled = true;
</script>
</body>
</html>